	private static void assertBenchmarkQueryCount(ThemeQueryBenchmark benchmark, Theme theme, int queryIndex) {
		long expected = ThemeQueryCatalog.expectedCountFor(theme, queryIndex);
		for (int repetition = 1; repetition <= QUERY_EXECUTION_REPETITIONS; repetition++) {
			assertEquals(expected, benchmark.executeQuery(),
					"Unexpected row count for " + theme + " query " + queryIndex + " on repetition " + repetition
							+ " of " + QUERY_EXECUTION_REPETITIONS);
		}
	}

	private static void setupWithSketches(ThemeQueryBenchmark benchmark) throws Exception {
		String previous = System.getProperty(ThemeQueryBenchmark.WAIT_FOR_SKETCHES_PROPERTY);
		try {
			System.setProperty(ThemeQueryBenchmark.WAIT_FOR_SKETCHES_PROPERTY, Boolean.TRUE.toString());
			benchmark.setup();
		} finally {
			if (previous == null) {
				System.clearProperty(ThemeQueryBenchmark.WAIT_FOR_SKETCHES_PROPERTY);
			} else {
				System.setProperty(ThemeQueryBenchmark.WAIT_FOR_SKETCHES_PROPERTY, previous);
			}
		}
	}

	private static List<Path> persistedSketchFiles(Path store) throws Exception {
		try (Stream<Path> paths = Files.find(store, 2,
				(path, attributes) -> attributes.isRegularFile()
						&& path.getFileName().toString().endsWith(".sketches"))) {
			return paths.sorted(Comparator.comparing(Path::toString)).collect(Collectors.toList());
		}
	}

	private static List<Long> lastModifiedMillis(List<Path> paths) throws Exception {
		List<Long> lastModified = new ArrayList<>(paths.size());
		for (Path path : paths) {
			lastModified.add(Files.getLastModifiedTime(path).toMillis());
		}
		return lastModified;
	}

